SELECT player_id, total_rounds_won, average_rank
FROM player_statistics
WHERE win_rate > 0.7;

SELECT player_id, SUM(comp_score) AS total_competitive_score
FROM tournament_results
GROUP BY player_id;

SELECT player_name 
FROM players 
WHERE player_id IN (
  SELECT DISTINCT player_id 
  FROM tournament_results
);
